public String getSandwich(String str) {
    String bread = "bread";
    int firstBreadIndex = str.indexOf(bread);
    int lastBreadIndex = str.lastIndexOf(bread);

    if (firstBreadIndex == -1 || lastBreadIndex == -1 || firstBreadIndex == lastBreadIndex) {
