            sum += nums[i];
        }
    }

    return sum;
}

public String plusOut(String str, String word)
{
    String result = "";
    for (int i = 0; i < str.length(); i++) {
        if (i + word.length() <= str.length() && str.substring(i, i + word.length()).equals(word)) {
            result += word;
            i += word.length() - 1;
        } else {
            result += "+";
        }
    }
    return result;
}

