public int blackjack(int a, int b) {
    // Check if both values are greater than 21
    if (a > 21 && b > 21) {
        return 0;
    }
    // Check if a is over 21
    else if (a > 21) {
        return b;
    }
    // Check if b is over 21
    else if (b > 21) {
        return a;
    }
    // Compare the difference between 21 and a with 21 and b
    else {
        if (21 - a <= 21 - b) {
            return a;
        } else {
            return b;
        }
    }
}

