public int[] shiftLeft(int[] nums) {
    if (nums.length <= 1) {
        return nums;
    }

    int[] shiftedArray = new int[nums.length];

    for (int i = 0; i < nums.length - 1; i++) {
        shiftedArray[i] = nums[i + 1];
    }

    shiftedArray[nums.length - 1] = nums[0];

    return shiftedArray;
}

