public int[] fix45(int[] nums) {
    int i = 0;

    while (i < nums.length) {
        if (nums[i] == 4 && (i == 0 || nums[i-1] != 4)) {
            int pos5 = find5(nums);
            nums[pos5] = nums[i+1];
            nums[i+1] = 5;
        }
        i++;
    }

    return nums;
}

private int find5(int[] nums) {
    for (int j = 0; j < nums.length; j++) {
        if (nums[j] == 5 && (j == 0 || nums[j-1] != 4)) {
            return j;
        }
    }
    return -1; // This should never happen if input array is valid
}

