                nums[pos] = temp;
            }
        }
    }
    return nums;
}

private int findNext5(int[] nums, int startIndex) {
    for (int j = 0; j < nums.length; j++) {
        if (nums[j] == 5) {
            if (j == 0 || nums[j - 1] != 4) {
                return j;
            }
        }
    }
    return -1; // Return -1 if we couldn't find a valid position for 5
}

