    int maxBigBars = goal / 5;
    if (big >= maxBigBars) {
        int remainingSmallBars = goal - (maxBigBars * 5);
        if (remainingSmallBars <= small) {
            return remainingSmallBars;
        }
    } else {
        int remainingKilos = goal - (big * 5);
        if (remainingKilos <= small) {
            return remainingKilos;
        }
    }
    return -1;
}

